 1	import React, { FC } from 'react';
 2	
 3	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getName } from '@kubevirt-utils/resources/shared';
 6	import { Text, TextVariants, Title } from '@patternfly/react-core';
 7	
 8	const CutomizeITVMHeader: FC = () => {
 9	  const { t } = useKubevirtTranslation();
10	  const {
11	    instanceTypeVMState: { selectedBootableVolume },
12	  } = useInstanceTypeVMStore();
13	
14	  return (
15	    <div className="pf-v6-c-page__main-breadcrumb wizard-header">
16	      <Title headingLevel="h1">{t('Customize and create VirtualMachine')}</Title>
17	      <Text component={TextVariants.small} data-test="wizard title help">
18	        {t('Bootable volume: {{bootableVolumeName}}', {
19	          bootableVolumeName: getName(selectedBootableVolume),
20	        })}
21	      </Text>
22	    </div>
23	  );
24	};
25	
26	export default CutomizeITVMHeader;

